import { OrderStateMachine, InvalidTransitionError, OrderState } from "./OrderStateMachine";

describe("OrderStateMachine", () => {
  let machine: OrderStateMachine;

  beforeEach(() => {
    machine = new OrderStateMachine();
  });

  // -----------------------------------------------------------------------
  // AC1 — Valid transitions
  // -----------------------------------------------------------------------
  describe("valid transitions (AC1)", () => {
    const cases: Array<[OrderState, OrderState]> = [
      ["PENDING",   "CONFIRMED"],
      ["CONFIRMED", "SHIPPED"],
      ["SHIPPED",   "DELIVERED"],
      ["CONFIRMED", "CANCELLED"],
      ["PENDING",   "CANCELLED"],
    ];

    test.each(cases)(
      "%s -> %s succeeds and returns target state",
      (from, to) => {
        expect(machine.transition(from, to)).toBe(to);
      },
    );
  });

  // -----------------------------------------------------------------------
  // AC2 — Invalid transitions throw INVALID_TRANSITION
  // -----------------------------------------------------------------------
  describe("invalid transitions throw INVALID_TRANSITION (AC2)", () => {
    const invalidCases: Array<[OrderState, OrderState]> = [
      ["DELIVERED", "SHIPPED"],    // AC2 example
      ["SHIPPED",   "PENDING"],    // AC2 example / AC6
      ["DELIVERED", "PENDING"],
      ["DELIVERED", "CONFIRMED"],
      ["DELIVERED", "CANCELLED"],
      ["DELIVERED", "DELIVERED"],
      ["SHIPPED",   "CONFIRMED"],
      ["SHIPPED",   "CANCELLED"],
      ["PENDING",   "SHIPPED"],
      ["PENDING",   "DELIVERED"],
    ];

    test.each(invalidCases)(
      "%s -> %s throws with code INVALID_TRANSITION",
      (from, to) => {
        expect(() => machine.transition(from, to)).toThrow();
        try {
          machine.transition(from, to);
        } catch (err) {
          expect((err as InvalidTransitionError).code).toBe("INVALID_TRANSITION");
        }
      },
    );
  });

  // -----------------------------------------------------------------------
  // AC3 — CANCELLED is a terminal state
  // -----------------------------------------------------------------------
  describe("CANCELLED is a terminal state (AC3)", () => {
    const targets: OrderState[] = ["PENDING", "CONFIRMED", "SHIPPED", "DELIVERED", "CANCELLED"];

    test.each(targets)("CANCELLED -> %s throws INVALID_TRANSITION", (to) => {
      expect(() => machine.transition("CANCELLED", to)).toThrow();
      try {
        machine.transition("CANCELLED", to);
      } catch (err) {
        expect((err as InvalidTransitionError).code).toBe("INVALID_TRANSITION");
      }
    });
  });

  // -----------------------------------------------------------------------
  // AC4 — DELIVERED is a terminal state
  // -----------------------------------------------------------------------
  describe("DELIVERED is a terminal state (AC4)", () => {
    const targets: OrderState[] = ["PENDING", "CONFIRMED", "SHIPPED", "DELIVERED", "CANCELLED"];

    test.each(targets)("DELIVERED -> %s throws INVALID_TRANSITION", (to) => {
      expect(() => machine.transition("DELIVERED", to)).toThrow();
      try {
        machine.transition("DELIVERED", to);
      } catch (err) {
        expect((err as InvalidTransitionError).code).toBe("INVALID_TRANSITION");
      }
    });
  });

  // -----------------------------------------------------------------------
  // AC5 — PENDING -> CONFIRMED happy path
  // -----------------------------------------------------------------------
  it("AC5: PENDING -> CONFIRMED returns CONFIRMED", () => {
    expect(machine.transition("PENDING", "CONFIRMED")).toBe("CONFIRMED");
  });

  // -----------------------------------------------------------------------
  // AC6 — SHIPPED -> PENDING throws
  // -----------------------------------------------------------------------
  it("AC6: SHIPPED -> PENDING throws INVALID_TRANSITION", () => {
    expect(() => machine.transition("SHIPPED", "PENDING")).toThrow();
    try {
      machine.transition("SHIPPED", "PENDING");
    } catch (err) {
      expect((err as InvalidTransitionError).code).toBe("INVALID_TRANSITION");
    }
  });

  // -----------------------------------------------------------------------
  // Error shape — message and name are informative
  // -----------------------------------------------------------------------
  it("error message includes both states", () => {
    try {
      machine.transition("DELIVERED", "SHIPPED");
      fail("expected throw");
    } catch (err) {
      const e = err as InvalidTransitionError;
      expect(e.message).toContain("DELIVERED");
      expect(e.message).toContain("SHIPPED");
      expect(e.name).toBe("InvalidTransitionError");
    }
  });

  it("error is instanceof Error", () => {
    try {
      machine.transition("CANCELLED", "PENDING");
    } catch (err) {
      expect(err).toBeInstanceOf(Error);
      expect(err).toBeInstanceOf(InvalidTransitionError);
    }
  });
});

